import React from 'react';
import { Link } from 'react-router-dom';

const ServiceCard = ({ servicio }) => {
  const { icon, bg, title, desc, features, link } = servicio;

  return (
    <div className="servicio-card" data-service={link.replace('#', '')}>
      <div className="servicio-bg" style={{ backgroundImage: `url(${bg})` }}></div>
      <div className="servicio-content">
        <div className="servicio-icon">
          <img src={icon} alt={title} />
        </div>
        <h3>{title}</h3>
        <p>{desc}</p>
        <ul className="servicio-features">
          {features.map((f, i) => (
            <li key={i}><i className="fas fa-check"></i> {f}</li>
          ))}
        </ul>
        <Link to={link} className="btn-servicio">Más Info</Link>
      </div>
    </div>
  );
};

export default ServiceCard;
